            {
                await connection.OpenAsync();
                log.LogInformation("Database connection opened successfully");

                string query = "SELECT * FROM Users WHERE UserId = @UserId AND Email = @Email";
                log.LogInformation($"SQL Query: {query}");

                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    command.Parameters.AddWithValue("@UserId", userId ?? (object)DBNull.Value);
                    command.Parameters.AddWithValue("@Email", email ?? (object)DBNull.Value);

                    log.LogInformation("=== QUERY PARAMETERS ===");
                    foreach (SqlParameter param in command.Parameters)
                    {
                        log.LogInformation($"Parameter: {param.ParameterName} = {param.Value} (Type: {param.SqlDbType})");
