            Exception innerEx = ex.InnerException;
            int level = 1;
            while (innerEx != null)
            {
                log.LogError($"=== INNER EXCEPTION LEVEL {level} ===");
                log.LogError($"Type: {innerEx.GetType().FullName}");
                log.LogError($"Message: {innerEx.Message}");
                log.LogError($"Stack Trace: {innerEx.StackTrace}");
                innerEx = innerEx.InnerException;
                level++;
            }

            log.LogError("=== REQUEST FAILED ===");
            return new StatusCodeResult(500);
        }
